{"cmd":"python3 -c "
import os, struct

with open('/app/alpine.iso', 'rb') as f:
    data = f.read()

# Find all file entries in ISO9660 directory structure
# Look for vmlinuz and initrd paths
for pattern in [b'vmlinuz', b'initrd', b'boot.img']:
    idx = 0
    while True:
        idx = data.find(pattern, idx)
        if idx < 0:
            break
        # Try to find the filename near this offset
        start = max(0, idx - 50)
        end = min(len(data), idx + 100)
        chunk = data[start:end]
        # Extract printable filename
        name = ''
        for b in chunk:
            if 32 <= b < 127:
                name += chr(b)
            else:
                name += ' '
        print(f'{pattern} at offset {idx}: ...{name}...')
        idx += 1
""}

